<span class="line"><span style="color:#89B4FA;font-style:italic;">    assert_eq!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">captures</span><span style="color:#9399B2;">,</span><span style="color:#89B4FA;font-style:italic;"> vec!</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;let&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;nombre&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;42&quot;</span><span style="color:#9399B2;">]);</span></span>
